"use client";
import { useState } from "react";
import Header from "@/components/Header";

export default function AdminPage() {
    const [tab, setTab] = useState("dashboard");
    const [showModal, setShowModal] = useState(false);
    const [modalType, setModalType] = useState("");

    const openModal = (type) => { setModalType(type); setShowModal(true); };
    const adminLinks = [
        { label: "Дашборд", href: "/admin", id: "dashboard" },
        { label: "Пользователи", href: "/admin?tab=users", id: "users" },
        { label: "Каталог", href: "/admin?tab=catalog", id: "catalog" },
        { label: "Выдачи", href: "/admin?tab=loans", id: "loans" },
        { label: "Аудит", href: "/admin?tab=audit", id: "audit" },
    ];

    return (
        <>
            <Header navLinks={adminLinks} user={{ name: "Алексей Д.", initials: "АД", role: "Администратор", email: "admin@lib.ru" }} notifCount={3} />

            <div className="admin-container">
                <div className="page-header">
                    <h1>Панель администратора</h1>
                    <p>Системный обзор — 21 апреля 2026</p>
                </div>

                {tab === "dashboard" && (
                    <>
                        <div className="stats-grid">
                            <div className="stat-card"><div className="stat-value" style={{color:'var(--cyan-400)'}}>3,842</div><div className="stat-label">Пользователей <span style={{color:'var(--green-400)'}}>+15%</span></div></div>
                            <div className="stat-card"><div className="stat-value">12,456</div><div className="stat-label">Книг в фонде <span style={{color:'var(--green-400)'}}>+8%</span></div></div>
                            <div className="stat-card"><div className="stat-value" style={{color:'var(--library-400)'}}>347</div><div className="stat-label">Активных выдач</div></div>
                            <div className="stat-card"><div className="stat-value" style={{color:'var(--red-400)'}}>₽45,200</div><div className="stat-label">Неоплаченных штрафов</div></div>
                        </div>

                        <div style={{display:'flex',gap:12,marginBottom:24,flexWrap:'wrap'}}>
                            <span className="server-badge st-ready">Основной сервер<br/><small>Uptime: 99.97%</small></span>
                            <span className="server-badge st-ready">База данных<br/><small>Загрузка: 42%</small></span>
                            <span className="server-badge st-waiting">Резервный сервер<br/><small>Синхронизация...</small></span>
                        </div>

                        <div className="table-wrap">
                            <h3 style={{padding:'16px 20px',borderBottom:'1px solid rgba(255,255,255,0.06)'}}>📜 Системный журнал (журнал_аудит)</h3>
                            <table>
                                <thead><tr><th>Действие</th><th>Пользователь</th><th>Время</th></tr></thead>
                                <tbody>
                                <tr><td>Изменение роли «Иван Петров» → старший_библиотекарь</td><td>Алексей Дмитриев</td><td>15 мин</td></tr>
                                <tr><td>Резервная копия БД успешно создана</td><td>Система</td><td>1 час</td></tr>
                                <tr><td>Обновление системы v2.4.1 → v2.4.2</td><td>Система</td><td>3 часа</td></tr>
                                <tr><td>Попытка входа: подозрительный IP 10.0.0.234</td><td>Система</td><td>5 часов</td></tr>
                                </tbody>
                            </table>
                        </div>
                    </>
                )}

                {tab === "users" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>👥 Пользователи</h3>
                            <button className="btn btn-primary btn-sm" onClick={()=>openModal('addUser')}>Добавить</button>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>ФИО</th><th>Email</th><th>Телефон</th><th>Роль</th><th>Заблокирован</th><th>Дата создания</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="8" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {tab === "catalog" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>📚 Каталог книг</h3>
                            <div style={{display:'flex',gap:8}}>
                                <button className="btn btn-secondary btn-sm" onClick={()=>openModal('addBook')}>Добавить книгу</button>
                                <button className="btn btn-secondary btn-sm" onClick={()=>openModal('addAuthor')}>Добавить автора</button>
                            </div>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Название</th><th>ISBN</th><th>Издательство</th><th>Год</th><th>Язык</th><th>Страниц</th><th>Всего</th><th>Доступно</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="10" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {tab === "audit" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>🔍 Журнал аудит</h3>
                            <button className="btn btn-secondary btn-sm">Экспорт</button>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Пользователь</th><th>Тип действия</th><th>Предмет действия</th><th>Предмет ID</th><th>IP адрес</th><th>Дата создания</th></tr></thead>
                            <tbody><tr><td colSpan="7" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}
            </div>

            {showModal && <AdminModal type={modalType} onClose={() => setShowModal(false)} />}
        </>
    );
}

function AdminModal({ type, onClose }) {
    const titles = { addUser: "Добавить пользователя", addBook: "Добавить книгу", addAuthor: "Добавить автора" };
    return (
        <div className="modal-overlay show" onClick={onClose}>
            <div className="modal" onClick={e=>e.stopPropagation()}>
                <button className="modal-close" onClick={onClose}>✕</button>
                <div className="modal-hero"><h2 className="modal-title">{titles[type] || "Форма"}</h2></div>
                <div className="modal-body">
                    {type === 'addUser' && (
                        <form style={{display:'grid',gap:16}}>
                            <label><span>ФИО *</span><input placeholder="Иванов Иван Иванович" /></label>
                            <label><span>Email *</span><input type="email" placeholder="user@mail.ru" /></label>
                            <label><span>Телефон</span><input type="tel" placeholder="+7 (900) 000-00-00" /></label>
                            <label><span>Роль *</span><select><option>Читатель</option><option>Библиотекарь</option><option>Администратор</option></select></label>
                        </form>
                    )}
                    {type === 'addBook' && (
                        <form style={{display:'grid',gap:16}}>
                            <label><span>Название *</span><input placeholder="Название книги" /></label>
                            <label><span>ISBN *</span><input placeholder="978-5-00000-000-0" /></label>
                            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12}}>
                                <label><span>Год издания</span><input type="number" defaultValue="2024" /></label>
                                <label><span>Издательство</span><input defaultValue="Эксмо" /></label>
                            </div>
                        </form>
                    )}
                </div>
                <div className="modal-footer">
                    <button className="btn btn-secondary btn-block" onClick={onClose}>Отмена</button>
                    <button className="btn btn-primary btn-block">Сохранить</button>
                </div>
            </div>
        </div>
    );
}